import random
import json
import time
from datetime import datetime

# Simulated sensor class for weather monitoring
class WeatherSensor:
 def __init__(self, sensor_id, sensor_type, unit):
 self.sensor_id = sensor_id
 self.sensor_type = sensor_type
 self.unit = unit

 def read_value(self):
 """Simulate reading sensor data with realistic ranges"""
 if self.sensor_type == "temperature":
 return round(random.uniform(15.0, 35.0), 2)
 elif self.sensor_type == "humidity":
 return round(random.uniform(30.0, 90.0), 2)
 elif self.sensor_type == "pressure":
 return round(random.uniform(990.0, 1030.0), 2)
 elif self.sensor_type == "wind_speed":
 return round(random.uniform(0.0, 25.0), 2)
 return 0.0

# Weather data packet structure
class WeatherDataPacket:
 def __init__(self):
 self.timestamp = None
 self.location = "university-Campus"
 self.sensors = {}

 def add_sensor_reading(self, sensor_id, value, unit):
 self.sensors[sensor_id] = {
 "value": value,
 "unit": unit
 }

 def to_json(self):
 return {
 "timestamp": self.timestamp,
 "location": self.location,
 "data": self.sensors
 }

# Simulated MQTT Publisher (using paho-mqtt pattern)
class MQTTPublisher:
 def __init__(self, broker_url, port):
 self.broker_url = broker_url
 self.port = port
 self.connected = False

 def connect(self):
 print(f"Connecting to MQTT broker at {self.broker_url}:{self.port}")
 self.connected = True
 print("Connected successfully!")

 def publish(self, topic, message):
 if self.connected:
 payload = json.dumps(message)
 print(f"Publishing to {topic}: {payload}")
 return True
 return False

# Main weather monitoring system
def main():
 # Initialize sensors
 sensors = [
 WeatherSensor("TEMP_001", "temperature", "°C"),
 WeatherSensor("HUM_001", "humidity", "%"),
 WeatherSensor("PRES_001", "pressure", "hPa"),
 WeatherSensor("WIND_001", "wind_speed", "m/s")
 ]

 # Initialize MQTT publisher
 publisher = MQTTPublisher("iot.weatherstation.cloud", 1883)
 publisher.connect()

 print("\n=== IoT Weather Monitoring System Started ===\n")

 # Continuous monitoring loop
 sampling_interval = 3 # seconds
 max_iterations = 5

 for i in range(max_iterations):
 # Collect sensor data
 data_packet = WeatherDataPacket()
 data_packet.timestamp = datetime.now().isoformat()

 for sensor in sensors:
 value = sensor.read_value()
 data_packet.add_sensor_reading(sensor.sensor_id, value, sensor.unit)
 print(f"{sensor.sensor_type}: {value} {sensor.unit}")

 # Publish to cloud
 publisher.publish("weather/campus/sensors", data_packet.to_json())

 print(f"--- Iteration {i+1} complete ---\n")
 time.sleep(sampling_interval)

 print("=== Weather Monitoring Session Ended ===")

if __name__ == "__main__":
 main()

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>

// Simulated hardware definitions for ESP32
#define ADC_TEMP_SENSOR 0
#define ADC_HUM_SENSOR 1
#define ADC_PRESS_SENSOR 2
#define ADC_WIND_SENSOR 3

#define WIFI_SSID "WeatherStation_Network"
#define MQTT_BROKER "iot.weatherstation.cloud"
#define MQTT_PORT 1883

// Sensor calibration offsets
#define TEMP_OFFSET -2.5
#define HUM_OFFSET 0.0
#define PRESS_OFFSET -5.0

// Data structures
typedef struct {
 float temperature; // Celsius
 float humidity; // Percentage
 float pressure; // hPa
 float wind_speed; // m/s
 char timestamp[32];
 char location[32];
} WeatherData;

typedef struct {
 char ssid[64];
 char password[64];
 int connected;
} WiFiConfig;

// Simulated ADC reading from sensors
float read_adc_sensor(int channel) {
 // Simulate ADC reading (returns raw 12-bit value 0-4095)
 // In real hardware, this would read from hardware registers
 return (float)(rand() % 4096);
}

// Convert raw ADC to physical units
float calibrate_sensor(int sensor_type, float raw_value) {
 float calibrated = 0.0;

 switch(sensor_type) {
 case ADC_TEMP_SENSOR:
 // LM35: 10mV per degree, ADC scale factor
 calibrated = (raw_value / 4096.0) * 3.3 * 100.0 + TEMP_OFFSET;
 break;

 case ADC_HUM_SENSOR:
 // DHT11 equivalent calculation
 calibrated = (raw_value / 4096.0) * 100.0 + HUM_OFFSET;
 break;

 case ADC_PRESS_SENSOR:
 // BMP280 equivalent calculation
 calibrated = (raw_value / 4096.0) * 200.0 + 800.0 + PRESS_OFFSET;
 break;

 case ADC_WIND_SENSOR:
 // Anemometer pulse counting
 calibrated = (raw_value / 4096.0) * 30.0;
 break;
 }

 return calibrated;
}

// Generate timestamp
void get_timestamp(char* buffer, size_t size) {
 time_t now = time(NULL);
 struct tm* tm_info = localtime(&now);
 strftime(buffer, size, "%Y-%m-%dT%H:%M:%SZ", tm_info);
}

