}

// Main weather monitoring function
void weather_station_loop(void) {
 WeatherData weather;
 WiFiConfig wifi = {0};

 strcpy(wifi.ssid, WIFI_SSID);

 // Initialize hardware
 printf("=== ESP32 Weather Station Initializing ===\n");
 wifi_init(&wifi);
 mqtt_connect();

 // Main monitoring loop
 int sample_count = 0;

 while (sample_count < 3) {
 // Read all sensors
 weather.temperature = calibrate_sensor(ADC_TEMP_SENSOR, 
 read_adc_sensor(ADC_TEMP_SENSOR));
 weather.humidity = calibrate_sensor(ADC_HUM_SENSOR, 
 read_adc_sensor(ADC_HUM_SENSOR));
 weather.pressure = calibrate_sensor(ADC_PRESS_SENSOR, 
 read_adc_sensor(ADC_PRESS_SENSOR));
 weather.wind_speed = calibrate_sensor(ADC_WIND_SENSOR, 
 read_adc_sensor(ADC_WIND_SENSOR));

 // Set metadata
 get_timestamp(weather.timestamp, sizeof(weather.timestamp));
 strcpy(weather.location, "university-Campus-01");

 // Print sensor readings
 printf("\n--- Sample %d ---\n", sample_count + 1);
 printf("Temperature: %.2f °C\n", weather.temperature);
 printf("Humidity: %.2f %\n", weather.humidity);
 printf("Pressure: %.2f hPa\n", weather.pressure);
 printf("Wind Speed: %.2f m/s\n", weather.wind_speed);
 printf("Timestamp: %s\n", weather.timestamp);

 // Create JSON payload (simplified)
 char payload[256];
 snprintf(payload, sizeof(payload), 
 "{\"temp\":%.2f,\"hum\":%.2f,\"pres\":%.2f,\"wind\":%.2f,\"loc\":\"%s\"}",
 weather.temperature, weather.humidity, weather.pressure,
 weather.wind_speed, weather.location);

 // Transmit to cloud
 mqtt_publish("weather/campus/sensors", payload);

 sample_count++;
 // In real code: vTaskDelay(pdMS_TO_TICKS(5000));
 }

 printf("\n=== Weather Station Shutdown ===\n");
}

// Entry point
int main(void) {
 srand(time(NULL)); // Seed for simulation
 weather_station_loop();
 return 0;
}

import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.web.bind.annotation.*;
import org.springframework.stereotype.Service;
import org.springframework.stereotype.Component;

import java.time.Instant;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

// Weather data model
class WeatherData {
 private String sensorId;
 private double temperature;
 private double humidity;
 private double pressure;
 private double windSpeed;
 private String location;
 private Instant timestamp;

 // Constructors
 public WeatherData() {}

 public WeatherData(String sensorId, double temperature, double humidity, 
 double pressure, double windSpeed, String location) {
 this.sensorId = sensorId;
 this.temperature = temperature;
 this.humidity = humidity;
 this.pressure = pressure;
 this.windSpeed = windSpeed;
 this.location = location;
 this.timestamp = Instant.now();
 }

 // Getters and Setters
 public String getSensorId() { return sensorId; }
 public void setSensorId(String sensorId) { this.sensorId = sensorId; }
 public double getTemperature() { return temperature; }
 public void setTemperature(double temperature) { this.temperature = temperature; }
 public double getHumidity() { return humidity; }
 public void setHumidity(double humidity) { this.humidity = humidity; }
 public double getPressure() { return pressure; }
 public void setPressure(double pressure) { this.pressure = pressure; }
 public double getWindSpeed() { return windSpeed; }
 public void setWindSpeed(double windSpeed) { this.windSpeed = windSpeed; }
 public String getLocation() { return location; }
 public void setLocation(String location) { this.location = location; }
 public Instant getTimestamp() { return timestamp; }
 public void setTimestamp(Instant timestamp) { this.timestamp = timestamp; }

 @Override
 public String toString() {
 return String.format("WeatherData{sensorId='%s', temp=%.2f°C, hum=%.2f%%, " +
 "pressure=%.2f hPa, wind=%.2f m/s, location='%s', timestamp=%s}",
 sensorId, temperature, humidity, pressure, windSpeed, location, timestamp);
 }
}

// Weather alert model
class WeatherAlert {
 private String alertType;
 private String message;
 private String severity;
 private Instant timestamp;

 public WeatherAlert(String alertType, String message, String severity) {
 this.alertType = alertType;
 this.message = message;
 this.severity = severity;
 this.timestamp = Instant.now();
 }

 public String getAlertType() { return alertType; }
 public String getMessage() { return message; }
 public String getSeverity() { return severity; }
 public Instant getTimestamp() { return timestamp; }
}

// In-memory data storage (simulates database)
@Component
class WeatherRepository {
 private final List<WeatherData> dataStore = new ArrayList<>();
 private final List<WeatherAlert> alerts = new ArrayList<>();

 public void save(WeatherData data) {
 dataStore.add(data);
 System.out.println("Stored weather data: " + data);
 }

 public List<WeatherData> findAll() {
 return new ArrayList<>(dataStore);
 }

 public List<WeatherData> findByLocation(String location) {
 return dataStore.stream()
 .filter(d -> d.getLocation().equals(location))
 .toList();
 }

 public void addAlert(WeatherAlert alert) {
 alerts.add(alert);
 System.out.println("ALERT GENERATED: [" + alert.getSeverity() + "] " + alert.getMessage());
 }

 public List<WeatherAlert> getAlerts() {
 return new ArrayList<>(alerts);
 }
}

// Weather analysis service
@Service
class WeatherAnalysisService {

 public Optional<WeatherAlert> analyzeWeather(WeatherData data) {
 // Check for high temperature
 if (data.getTemperature() > 40.0) {
 return Optional.of(new WeatherAlert(
 "EXTREME_HEAT",
 "Temperature exceeds 40°C - Heat wave warning",
 "HIGH"
 ));
 }

 // Check for low temperature
 if (data.getTemperature() < 5.0) {
 return Optional.of(new WeatherAlert(
 "FREEZE",
 "Temperature below 5°C - Frost warning",
 "MEDIUM"
 ));
 }

 // Check for high wind
 if (data.getWindSpeed() > 20.0) {
 return Optional.of(new WeatherAlert(
 "HIGH_WIND",
 "Wind speed exceeds 20 m/s - Storm warning",
 "HIGH"
 ));
 }

 // Check for low pressure (storm indication)
 if (data.getPressure() < 1000.0) {
 return Optional.of(new WeatherAlert(
 "LOW_PRESSURE",
 "Rapidly dropping pressure - Storm approaching",
 "MEDIUM"
 ));
 }

 return Optional.empty();
 }

 public Map<String, Double> calculateStatistics(List<WeatherData> dataList) {
 if (dataList.isEmpty()) {
 return Map.of();
 }

 double avgTemp = dataList.stream().mapToDouble(WeatherData::getTemperature).average().orElse(0);
 double avgHum = dataList.stream().mapToDouble(WeatherData::getHumidity).average().orElse(0);
 double avgPres = dataList.stream().mapToDouble(WeatherData::getPressure).average().orElse(0);

 Map<String, Double> stats = new HashMap<>();
 stats.put("avgTemperature", avgTemp);
 stats.put("avgHumidity", avgHum);
 stats.put("avgPressure", avgPres);
 stats.put("totalReadings", (double) dataList.size());

 return stats;
 }
}

// REST Controller for IoT device communication
@RestController
@RequestMapping("/api/weather")
class WeatherController {

 private final WeatherRepository repository;
 private final WeatherAnalysisService analysisService;

 public WeatherController(WeatherRepository repository, WeatherAnalysisService analysisService) {
 this.repository = repository;
 this.analysisService = analysisService;
 }

 // Endpoint for IoT devices to send data
 @PostMapping("/ingest")
 public String ingestWeatherData(@RequestBody WeatherData data) {
 System.out.println("Received data from sensor: " + data.getSensorId());

 // Store the data
 repository.save(data);

 // Analyze for weather patterns and alerts
 analysisService.analyzeWeather(data).ifPresent(alert -> {
 repository.addAlert(alert);
 });

 return "Data ingested successfully";
 }

 // Endpoint to retrieve all weather data
 @GetMapping("/data")
 public List<WeatherData> getAllWeatherData() {
 return repository.findAll();
 }

 // Endpoint to get data by location
 @GetMapping("/data/{location}")
 public List<WeatherData> getWeatherByLocation(@PathVariable String location) {
 return repository.findByLocation(location);
 }

 // Endpoint to get weather alerts
 @GetMapping("/alerts")
 public List<WeatherAlert> getAlerts() {
 return repository.getAlerts();
 }

 // Endpoint for statistics
 @GetMapping("/statistics")
 public Map<String, Double> getStatistics(@RequestParam(required = false) String location) {
 List<WeatherData> data = (location != null) ? 
 repository.findByLocation(location) : 
 repository.findAll();
 return analysisService.calculateStatistics(data);
 }
}

